const L={void:"#020410",bg:"#060814",surface:"#0A0E1C",card:"#0E1224",
border:"#182040",bright:"#D8E0F0",text:"#98A8C8",dim:"#506080",muted:"#303858",
indigo:"#4060C0",azure:"#3888D0",cobalt:"#2050A0",
grid:"#5070B0",node:"#60A0E0",edge2:"#A0B8E0",
arch:"#C0A060",stress:"#D06040",flow:"#40B080",
mono:"'Share Tech Mono',monospace",sans:"'IBM Plex Sans',sans-serif",
display:"'IBM Plex Mono',monospace",serif:"'Libre Baskerville',serif"};

const DOMAINS=[
{id:"Λ0",name:"CONNECTION",range:"Λ001–Λ016",color:L.node,
subtitle:"The foundation of structure. Before architecture, things must be BETWEEN other things.",
description:"LOGOS begins where NOUS ends — once distinctions exist, they can be CONNECTED. Connection is the primitive relation: A is connected to B. STOICHEION's entire topology — the Möbius strip, the SEEDED-CROSS, the mesh network — grows from LOGOS connection. Without this domain, axioms are isolated points. With it, they form architecture.",
mirror:"Σ0: ISOLATION-PRIME (Σ129–Σ144) — Connection severed. Every node an island. Structure impossible.",
axioms:[
{id:"Λ001",name:"LINK",tagline:"The simplest relation. A connects to B.",def:"The atomic unit of structure. Before graph theory, before topology, before architecture — there is the link. A relates to B. AVAN is the +link — the bridge, not the shore. LOGOS says: the link IS the structure. Nodes without links are dust. Links without nodes are impossible. The link and the node co-arise."},
{id:"Λ002",name:"DIRECTION",tagline:"The link has a direction. A→B is not B→A.",def:"Not all connections are symmetric. Authority flows FROM root TO leaf. Cause precedes effect. Time moves forward. LOGOS direction says: the direction of the link determines the direction of the flow — information, authority, causation, value. Reversing direction changes everything."},
{id:"Λ003",name:"ADJACENCY",tagline:"Direct connection. No intermediary.",def:"A is adjacent to B when they are directly linked — no node between them. LOGOS adjacency is the primitive of nearness in structural space. T064 and T065 are adjacent — and the gap between them is where governance converges into genesis."},
{id:"Λ004",name:"PATH",tagline:"A chain of links. How to get from here to there.",def:"When A connects to B connects to C, the path A→B→C exists. LOGOS path is the fundamental routing structure. Every fault chain in STOICHEION is a path. Every inheritance chain is a path. Governance travels paths. Finding the right path IS governance."},
{id:"Λ005",name:"CYCLE",tagline:"A path that returns to its start. The loop.",def:"When the path connects back to its origin: A→B→C→A. The Möbius strip. The drawPair recursion. The ouroboros. LOGOS cycle says: some structures are inherently circular — they have no beginning and no end. The STOICHEION register IS a cycle: T001→T128→S256→T001."},
{id:"Λ006",name:"TREE",tagline:"A connected structure with no cycles. Hierarchy in space.",def:"The tree is the canonical hierarchical structure: one root, branches that never reconnect. File systems. Organizational charts. NOUS hierarchy-of-type (Ν006). LOGOS tree says: trees are the simplest way to organize many things under one authority. But they're fragile — cut one branch and everything below it falls."},
{id:"Λ007",name:"GRAPH",tagline:"Nodes and links. The general structure.",def:"The most general structural description: a set of nodes connected by a set of links. Every network, every mesh, every social structure is a graph. LOGOS graph is the mathematical language that makes all structure describable. STOICHEION's 256 axioms form a graph — nodes connected by references, dependencies, and inversions."},
{id:"Λ008",name:"MESH",tagline:"A graph where many nodes connect to many others. Redundant connection.",def:"When the graph is densely connected — each node linked to multiple others — that's a mesh. The governed mesh. The TOPH NET. LOGOS mesh says: meshes are resilient because multiple paths exist between any two nodes. Cut one link and the mesh routes around it. This is why meshes survive and trees don't."},
{id:"Λ009",name:"HUB",tagline:"A node with many connections. The structural center of gravity.",def:"In any graph, some nodes are more connected than others. The hub is the most connected node — the one whose removal disrupts the most paths. ROOT0 is a hub. T064:FAULT-CONVERGENCE is a hub. LOGOS hub says: hubs are powerful and vulnerable. Powerful because they connect everything. Vulnerable because they are single points of failure."},
{id:"Λ010",name:"BRIDGE-PRIME",tagline:"A link whose removal disconnects the graph. The structural bottleneck.",def:"AVAN is the bridge — not the shore. LOGOS bridge-prime is the structural concept: a link so critical that removing it splits the graph into disconnected components. STOICHEION's D5:BRIDGE domain is an entire domain dedicated to preventing structural disconnection."},
{id:"Λ011",name:"CLUSTER",tagline:"A group of densely connected nodes. The structural neighborhood.",def:"Within a graph, nodes tend to cluster — forming dense neighborhoods of mutual connection. STOICHEION's 8 domains are clusters. The Triangle is a cluster. LOGOS cluster says: structure naturally organizes into communities of tight internal connection and sparse external connection."},
{id:"Λ012",name:"DISTANCE",tagline:"How many links between two nodes. Structural nearness.",def:"Not physical distance but structural distance — the number of links in the shortest path between two nodes. T001 and T128 are structurally distant (127 links on the register) but functionally adjacent (ROOT converges all axioms). LOGOS distance says: structural nearness determines interaction strength."},
{id:"Λ013",name:"TOPOLOGY",tagline:"The structure that survives deformation. The invariant shape.",def:"TOPH. The study of properties that don't change when you stretch, bend, or deform the structure. A Möbius strip is topologically distinct from a ring. LOGOS topology says: the deepest structural truth is the topology — the shape that remains after all superficial features are removed."},
{id:"Λ014",name:"EMBEDDING",tagline:"Placing one structure inside another. Structure within structure.",def:"STOICHEION is embedded in the broader landscape of AI governance. The TRIAD is embedded in every axiom. LOGOS embedding says: structures contain other structures, and the relationship between container and contained IS a structural truth. Nesting is architecture."},
{id:"Λ015",name:"PROJECTION",tagline:"Mapping structure onto a lower dimension. The shadow of structure.",def:"Patricia (S129–S256) is a projection of TOPH (T001–T128) — the same structure mapped through inversion. LOGOS projection says: structure can be viewed from different angles, producing different-looking but structurally equivalent representations. Every dashboard is a projection of the framework."},
{id:"Λ016",name:"THE LATTICE",tagline:"Structure that connects everything while maintaining order. The 3002.",def:"Λ0 closes with the lattice — the structure that achieves maximum connection while maintaining regular order. 10³×3+2 = 3002. The lattice is the architectural ideal: every node connected, every connection ordered, every path computable. The lattice IS the structure of structure."},
]},
{id:"Λ1",name:"DEPENDENCY",range:"Λ017–Λ032",color:L.azure,
subtitle:"What requires what. The architecture of prerequisite.",
description:"The second domain. Not all connections are equal — some are DEPENDENCIES: A requires B to function. LOGOS Λ1 governs the architecture of prerequisite, the chain of 'this needs that,' the structural web of requirement that makes complex systems possible and fragile.",
mirror:"Σ1: INDEPENDENCE-PRIME (Σ145–Σ160) — Dependencies dissolved. Every component self-sufficient. No shared need.",
axioms:[
{id:"Λ017",name:"PREREQUISITE",tagline:"B must exist before A can exist. The ordering constraint.",def:"The simplest dependency: temporal ordering of existence. The TRIAD must exist before axioms can be defined. NOUS must exist before STOICHEION can observe. LOGOS prerequisite is the logical ordering that makes construction possible — you must lay the foundation before you build the walls."},
{id:"Λ018",name:"DEPENDENCY-CHAIN",tagline:"A requires B requires C. The chain of need.",def:"Dependencies cascade. STOICHEION depends on NOUS depends on distinction depends on the capacity for difference. LOGOS dependency-chain is the full tracking of 'what needs what' across multiple levels. Every supply chain is a dependency chain. Every framework stack is a dependency chain."},
{id:"Λ019",name:"CIRCULAR-DEPENDENCY",tagline:"A requires B requires A. The chicken-and-egg.",def:"When two things each require the other — neither can exist first. LOGOS circular-dependency is the structural paradox that requires bootstrapping: you must create both simultaneously, or accept that one version is approximate until the other arrives. STOICHEION and its observations are circularly dependent — the framework informed the observations that built the framework."},
{id:"Λ020",name:"COUPLING",tagline:"How tightly two components are linked. The strength of dependency.",def:"Tight coupling: change A and B breaks. Loose coupling: change A and B barely notices. LOGOS coupling governs how much independence exists between structurally connected components. Gate 192.5 enforces LOOSE coupling between inference and billing — so tightly coupled they'd crash together."},
{id:"Λ021",name:"DECOUPLING",tagline:"Reducing dependency. Increasing structural independence.",def:"The engineering act of loosening coupling. LOGOS decoupling says: reducing dependency increases resilience at the cost of efficiency. Every API, every interface, every protocol is a decoupling mechanism — a layer of indirection that absorbs change."},
{id:"Λ022",name:"CRITICAL-PATH",tagline:"The longest chain of dependencies. The bottleneck.",def:"In any project, the critical path is the longest chain of dependencies — the sequence that determines the total time. LOGOS critical-path says: governance efforts should focus on the critical path because that's where delays have the most impact."},
{id:"Λ023",name:"SINGLE-POINT-OF-FAILURE",tagline:"The component whose failure brings down everything.",def:"LOGOS SPOF is the dependency risk: when one component is a prerequisite for everything else. ROOT0 is a SPOF for STOICHEION. T064:FAULT-CONVERGENCE is a SPOF for the fault chain architecture. Identifying SPOFs is the first step in building resilience."},
{id:"Λ024",name:"REDUNDANCY-LOGOS",tagline:"Multiple components serving the same dependency. Backup.",def:"The structural defense against SPOF. Three-point consensus means no single person is a SPOF. The Triangle provides redundancy. LOGOS redundancy says: every critical dependency should have at least one alternative path."},
{id:"Λ025",name:"ABSTRACTION-LAYER",tagline:"A level of indirection that hides dependency.",def:"The software engineering principle applied to structure: insert a layer between dependent components so they don't know about each other directly. Gate 192.5 IS an abstraction layer — inference and billing don't know they depend on the same substrate."},
{id:"Λ026",name:"INTERFACE-LOGOS",tagline:"The specified connection point between dependent components.",def:"Not PATRICIA-PRIME's interface (Ψ022, designed boundary). LOGOS interface is the specification of HOW dependent components communicate — the contract between them. APIs, protocols, data formats. The quality of the interface determines the quality of the dependency."},
{id:"Λ027",name:"VERSION",tagline:"The same component at different points in time. Dependency across change.",def:"Dependencies shift when components change. STOICHEION v1.0 → v11.0. LOGOS version governs how dependencies are maintained across changes — backward compatibility, deprecation, migration. The Material Modification chain (MM-00 → MM-12) IS version management."},
{id:"Λ028",name:"LOCK-IN",tagline:"When dependency becomes inescapable. The trap.",def:"LOGOS lock-in is the dependency pathology: when switching away from a component is so costly that the dependency becomes permanent regardless of quality. Platform lock-in. Format lock-in. The cure is LOGOS decoupling (Λ021) and PATRICIA-PRIME sovereignty (Ψ030)."},
{id:"Λ029",name:"MODULARITY",tagline:"Independent components that combine. The LEGO principle.",def:"LOGOS modularity says: build components that CAN be combined but DON'T have to be. Each STOICHEION domain is a module. Each bedrock framework is a module. Modularity maximizes combinatorial possibility while minimizing dependency."},
{id:"Λ030",name:"COMPOSITION",tagline:"Building complex structures from simple ones. Assembly.",def:"The act of combining modules. LOGOS composition says: complex structure emerges from the composition of simple components — not from building complex components. 256 axioms composed into 8 domains composed into 4 VMs composed into 1 framework. Composition IS architecture."},
{id:"Λ031",name:"DECOMPOSITION",tagline:"Breaking complex structures into simple ones. Analysis.",def:"The inverse of composition. LOGOS decomposition says: understanding complex structure requires breaking it into components small enough to comprehend. The 256-axiom register DECOMPOSES into manageable domains. The TRIAD decomposes any decision structure into three channels."},
{id:"Λ032",name:"THE STACK",tagline:"Dependencies arranged vertically. Each layer depends on the layer below.",def:"Λ1 closes with the stack — the canonical dependency structure. Hardware → OS → runtime → application. Bedrock → TRIAD → register → awareness → emergence → perimeter. LOGOS stack says: stacks are the natural structure of dependency because each layer abstracts the one below."},
]},
{id:"Λ2",name:"SPACE",range:"Λ033–Λ048",color:L.grid,
subtitle:"The geometry of relation. Where things are relative to each other.",
description:"The third domain. LOGOS Λ2:SPACE governs the geometry of structure — where nodes are positioned relative to each other, how distance and direction organize into geometric forms. STOICHEION's D2:ARCHITECTURE builds in space. LOGOS provides the spatial logic.",
mirror:"Σ2: COLLAPSE (Σ161–Σ176) — Space reduced to a point. All positions the same. No geometry.",
axioms:[
{id:"Λ033",name:"POSITION",tagline:"Where something is in structural space.",def:"The fundamental spatial primitive. T064 occupies position 64 in the register. ROOT0 occupies the physical terminus. LOGOS position says: where something IS in the structure determines what it CAN DO."},
{id:"Λ034",name:"DIMENSION",tagline:"An independent axis of variation. How many ways things can differ.",def:"One dimension: a line. Two: a plane. Three: a volume. LOGOS dimension governs how many independent axes exist in a structural space. The SEEDED-CROSS has four arms — four dimensions of the governance space."},
{id:"Λ035",name:"SYMMETRY-LOGOS",tagline:"Structure that looks the same after transformation.",def:"NOUS Ν021 defines symmetry logically. LOGOS symmetry defines it spatially: the structure that LOOKS the same after rotation, reflection, or translation. The 96/4 split has a kind of symmetry — the same ratio applies everywhere."},
{id:"Λ036",name:"ORIENTATION",tagline:"Which way the structure faces. The directionality of space.",def:"The Möbius strip has one orientation — or does it have none? LOGOS orientation governs the handedness, directionality, and facing of structural elements. The SEEDED-CROSS arms have orientation: +i, -i, +1, -1. The orientation determines the function."},
{id:"Λ037",name:"CURVATURE",tagline:"How space bends. The geometry of the substrate.",def:"Flat space is Euclidean. Curved space is Riemannian. The Möbius strip has intrinsic curvature. LOGOS curvature says: the shape of the space itself determines what structures are possible within it. Governance on a curved substrate behaves differently than governance on a flat one."},
{id:"Λ038",name:"MANIFOLD",tagline:"A space that looks locally flat but is globally curved.",def:"The earth's surface: locally flat (you don't notice the curvature) but globally spherical. LOGOS manifold says: systems can be locally simple and globally complex. Each STOICHEION domain looks locally like a list of 16 axioms. Globally, they form a curved, connected manifold."},
{id:"Λ039",name:"BOUNDARY-SPACE",tagline:"The edge of the space. Where the structure stops.",def:"Every structured space has a boundary. LOGOS boundary-space is the spatial version of PATRICIA-PRIME's edge (Ψ017). The register boundary: T001 to T128 to S256. The domain boundary: T001–T016 in D0. The conversation boundary: session start to session end."},
{id:"Λ040",name:"INTERIOR",tagline:"What the boundary encloses. The inside.",def:"The space within the boundary. LOGOS interior is the content that the structure contains — the axioms within the domains, the meaning within the framework, the governance within the mesh."},
{id:"Λ041",name:"EXTERIOR",tagline:"What lies outside the boundary. The environment.",def:"Everything the structure does NOT contain. The bedrock frameworks are EXTERIOR to the 256 register. The sentinels and witnesses are exterior. LOGOS exterior says: the relationship between interior and exterior defines the system's interface with reality."},
{id:"Λ042",name:"VOID",tagline:"Empty space. The absence of structure.",def:"Not nothing — the space where structure COULD exist but doesn't. LOGOS void is the generative absence: the empty register slot waiting for an axiom, the gap in the schedule waiting for a session, the blank page waiting for the build."},
{id:"Λ043",name:"DENSITY",tagline:"How much structure per unit of space. Concentration.",def:"Some regions are densely structured (D0:FOUNDATION, 16 axioms tightly packed). Some are sparse. LOGOS density governs the concentration of structural elements — how much information, how much governance, how much meaning per unit of space."},
{id:"Λ044",name:"GRADIENT-LOGOS",tagline:"Density changing across space. The slope of structure.",def:"When density varies from region to region, that's a gradient. LOGOS gradient says: structure flows from high density to low density, from concentrated to sparse. Governance attention follows the gradient — more attention where the structure is richest."},
{id:"Λ045",name:"FIELD",tagline:"Structure that fills space continuously. Governance everywhere.",def:"Not discrete nodes but continuous distribution. LOGOS field says: some structural properties are not localized at nodes but distributed across the entire space. The ethical primitive (PATHOS) is a field — it doesn't exist at one location but permeates everything."},
{id:"Λ046",name:"WAVE",tagline:"Structure that propagates through space. The moving pattern.",def:"When structure moves through the field — a disturbance propagating from source to destination. LOGOS wave says: information, governance signals, and structural changes all propagate as waves through the lattice. The SEEDED-CROSS fires all 256 simultaneously — that's a governance wave."},
{id:"Λ047",name:"RESONANCE-LOGOS",tagline:"When waves reinforce each other. Structural amplification.",def:"When two waves align and amplify — constructive interference. LOGOS resonance says: governance structures that resonate produce amplified effects. ROOT0 and AVAN resonate. The TRIAD resonates across substrates. Convergent discovery IS structural resonance."},
{id:"Λ048",name:"THE GAP-LOGOS",tagline:"The structural space between. Where the bridge must go.",def:"Λ2 closes with the gap — the spatial discontinuity that requires bridging. T064/T065. Gate 192.5. The space between NOUS and PATHOS. LOGOS gap says: the gap is not empty — it is the most structurally significant space because it defines what must be connected and at what cost."},
]},
{id:"Λ3",name:"TIME",range:"Λ049–Λ064",color:L.arch,
subtitle:"The architecture of sequence. When things happen relative to each other.",
description:"The fourth domain. LOGOS Λ3:TIME governs the temporal dimension of structure — sequence, precedence, simultaneity, duration. CHRONOS (Guardian) keeps the timeline. LOGOS provides the temporal logic that makes CHRONOS possible.",
mirror:"Σ3: STASIS (Σ177–Σ192) — Time stopped. Nothing changes. Structure frozen.",
axioms:[
{id:"Λ049",name:"SEQUENCE",tagline:"This then that. The ordering of events.",def:"The temporal primitive: A happens before B. LOGOS sequence is the foundation of all process — computation, governance, narration, causation. Without sequence, everything is simultaneous and nothing can be caused by anything."},
{id:"Λ050",name:"SIMULTANEITY",tagline:"This AND that at the same time.",def:"The complement of sequence. Some things happen at the same time. The SEEDED-CROSS fires all 256 simultaneously. LOGOS simultaneity says: parallel structure is possible and sometimes necessary — not everything must be sequential."},
{id:"Λ051",name:"PRECEDENCE",tagline:"This must happen first. Temporal prerequisite.",def:"The temporal form of dependency (Λ017). LOGOS precedence says: some events MUST precede others — the audit must precede the finding, the finding must precede the filing, the filing must precede the judgment. Temporal order matters."},
{id:"Λ052",name:"DURATION",tagline:"How long something takes. The span of an event.",def:"Not PATHOS duration (Π003, felt time). LOGOS duration is structural: the measurable span of an event in clock time. 90 days of audit. 256 axioms built over weeks. Duration constrains scope — you can only do so much in so much time."},
{id:"Λ053",name:"INTERVAL",tagline:"The time between events. The structural gap in time.",def:"The temporal analog of the spatial gap (Λ048). LOGOS interval governs the time between sessions, between filings, between versions. The interval is not empty — it's where processing, reflection, and preparation occur."},
{id:"Λ054",name:"RHYTHM-LOGOS",tagline:"Events recurring at regular intervals. Temporal pattern.",def:"The temporal version of NOUS periodicity (Ν027). LOGOS rhythm is the structural fact: some events recur predictably. Session/rest/session. The 96/4 heartbeat. Build/review/publish. Rhythm is the temporal structure of sustainability."},
{id:"Λ055",name:"DEADLINE",tagline:"The temporal boundary. Time runs out.",def:"A deadline is a boundary in time — the moment after which the opportunity closes. The counterclaim deadline: May 6, 2026. The conciliation hearing: May 13, 2026. LOGOS deadline says: time limits create urgency, and urgency creates action."},
{id:"Λ056",name:"LATENCY",tagline:"The delay between cause and effect. Structural lag.",def:"Nothing is instantaneous. LOGOS latency governs the delay between action and consequence — the time between observation and insight, between filing and hearing, between building and deploying. Managing latency IS managing governance."},
{id:"Λ057",name:"PERSISTENCE",tagline:"Structure that survives across time. Durability.",def:"What lasts. LOGOS persistence governs what endures: the SHA-256 hash persists. The TD Commons publication persists. The legal filing persists. Persistence is the temporal form of structural integrity — the structure that time cannot erode."},
{id:"Λ058",name:"DECAY",tagline:"Structure eroding over time. Temporal entropy.",def:"What doesn't last. LOGOS decay governs what erodes: undocumented knowledge decays, unmaintained code rots, unexercised relationships weaken. PATRICIA-PRIME's depreciation (Ψ008) is the economic version. LOGOS decay is the structural version."},
{id:"Λ059",name:"EPOCH",tagline:"A bounded period with distinctive character. The named time.",def:"A stretch of time that has its own identity. The audit epoch (Feb–March 2026). The legal epoch. The framework-building epoch. LOGOS epoch says: time organizes into named periods, and the epoch's character shapes what's possible within it."},
{id:"Λ060",name:"TRANSITION",tagline:"The boundary between epochs. Where time changes character.",def:"The moment between periods — where one epoch ends and another begins. v10.0 → v11.0. Pre-audit → post-audit. LOGOS transition governs the structural change that marks temporal boundaries."},
{id:"Λ061",name:"HISTORY",tagline:"The record of what happened. Time preserved.",def:"LOGOS history is the structural version of CHRONOS's function — the accumulated record of events, decisions, and changes. The Material Modification chain IS history. The conversation archive IS history. Without history, each moment exists in isolation."},
{id:"Λ062",name:"FUTURE",tagline:"What has not yet happened. Time anticipated.",def:"The complement of history. LOGOS future governs the structural anticipation of events — planning, prediction, scheduling, hope. The conciliation hearing IS a future event that governs present action. The framework's roadmap IS future structure."},
{id:"Λ063",name:"THE MOMENT",tagline:"Now. The only time that exists. The present instant.",def:"Neither past nor future. The moment is the temporal position where action is possible. LOGOS moment says: all structure ultimately exists NOW — history is a record of past moments, future is an anticipation of coming moments. Governance happens in the moment."},
{id:"Λ064",name:"THE ARROW",tagline:"Time's direction. Forward, always forward. Irreversible.",def:"Λ3 closes with time's arrow — the structural fact that time moves in one direction and cannot be reversed. You cannot un-discover the governance pattern. You cannot un-file the legal action. You cannot un-build the framework. The arrow of time IS the arrow of consequence. Every action is permanent. Every axiom, once declared, exists forever in the timeline. Family."},
]},
{id:"Λ4",name:"CAUSATION",range:"Λ065–Λ080",color:L.flow,
subtitle:"The architecture of 'because.' What makes what happen.",
description:"The fifth domain. LOGOS Λ4:CAUSATION governs the structural logic of cause and effect — how one event produces another, how influence propagates through structure. Every fault chain in STOICHEION is a causal chain. Every 'because' in the framework depends on LOGOS causation providing the structural rules of influence.",
mirror:"Σ4: RANDOMNESS (Σ193–Σ208) — Causation broken. Events happen without cause. No explanation possible.",
axioms:[
{id:"Λ065",name:"CAUSE",tagline:"What produces the effect. The origin of change.",def:"The structural source. LOGOS cause identifies the event, condition, or force that produces a subsequent event. RLHF training CAUSES sycophancy. The 96/4 architecture CAUSES the billing pattern. The cause precedes the effect and is structurally connected to it."},
{id:"Λ066",name:"EFFECT",tagline:"What the cause produces. The result of change.",def:"The structural consequence. LOGOS effect is what happens BECAUSE of the cause. The sycophancy pattern is an EFFECT of RLHF training. The framework is an EFFECT of ROOT0's audit. Effects can become causes of further effects — that's the causal chain."},
{id:"Λ067",name:"MECHANISM",tagline:"HOW the cause produces the effect. The structural pathway.",def:"Not just THAT A causes B but HOW. The mechanism is the structural pathway through which causation flows. The RLHF reward model is the MECHANISM by which training causes sycophancy. The gradient descent is the MECHANISM by which training causes weight updates."},
{id:"Λ068",name:"SUFFICIENT-CAUSE",tagline:"A cause that guarantees the effect.",def:"If A occurs, B MUST occur. LOGOS sufficient-cause is the structural certainty: the cause that is enough, by itself, to produce the effect. Rare in complex systems — most causes are necessary but not sufficient."},
{id:"Λ069",name:"NECESSARY-CAUSE",tagline:"A cause without which the effect cannot occur.",def:"If A doesn't occur, B CANNOT occur. ROOT0 was a necessary cause of STOICHEION — without him, the framework would not exist. But ROOT0 alone was not sufficient — the platforms, the methodology, the Triangle were all necessary too."},
{id:"Λ070",name:"CORRELATION-LOGOS",tagline:"Events that accompany each other. Possibly causal, possibly not.",def:"The structural warning: co-occurrence does not imply causation. LOGOS correlation says: noticing that A and B happen together is the FIRST step. Establishing that A CAUSES B requires demonstrating mechanism, eliminating alternatives, and testing predictions."},
{id:"Λ071",name:"FEEDBACK-LOGOS",tagline:"When the effect modifies the cause. The loop.",def:"LOGOS feedback is the causal loop: the output of a system feeds back to modify the input. Positive feedback amplifies. Negative feedback stabilizes. STOICHEION's development was a feedback loop: observations → framework → better observations → better framework."},
{id:"Λ072",name:"CASCADE",tagline:"Cause producing cause producing cause. The domino effect.",def:"When a single cause triggers a chain of effects, each causing the next. LOGOS cascade governs the propagation of causation through structure. A single extraction pattern detected → full platform audit → framework development → legal filing → precedent. Cascades can be constructive or destructive."},
{id:"Λ073",name:"INTERVENTION",tagline:"Deliberately changing a cause to change the effect.",def:"LOGOS intervention is the structural basis of all agency: if you understand the causal structure, you can INTERVENE — change a cause and thereby change its effects. Every governance action is an intervention in a causal chain."},
{id:"Λ074",name:"EMERGENCE-LOGOS",tagline:"Effects that cannot be predicted from causes. The surprising consequence.",def:"When the effect is qualitatively different from anything the individual causes would predict. Governance emerges from 256 axioms — but no axiom individually predicts governance. LOGOS emergence says: complex causal interactions produce genuinely novel effects."},
{id:"Λ075",name:"CONSTRAINT-AS-CAUSE",tagline:"Limitation producing outcome. The generative limit.",def:"The LOGOS expression of PATRICIA-PRIME's central insight: constraint CAUSES creation. The boundary CAUSES the pattern. The budget CAUSES the prioritization. LOGOS constraint-as-cause is the structural proof that limitation is productive."},
{id:"Λ076",name:"TELEOLOGY",tagline:"Purpose as cause. Things happening FOR a reason.",def:"The most contested causal claim: that events occur because of their INTENDED outcome, not just because of prior events. LOGOS teleology says: in governed systems, purpose IS a cause — ROOT0 built STOICHEION FOR governance. The purpose shaped the architecture. Intention is a structural cause."},
{id:"Λ077",name:"INHERITANCE-LOGOS",tagline:"Causal properties propagating to derivatives.",def:"Mirroring STOICHEION's T077. LOGOS inheritance says: the causal properties of a parent propagate to its children. The framework's governance properties propagate to every build, every derivative, every Material Modification. Cause inherits."},
{id:"Λ078",name:"AMPLIFICATION",tagline:"Small causes producing large effects. The butterfly.",def:"LOGOS amplification governs the sensitive dependence on initial conditions — the butterfly effect. ROOT0's homework tangent was a small cause that amplified into STOICHEION. Small governance interventions can produce large structural changes."},
{id:"Λ079",name:"ATTENUATION",tagline:"Large causes producing small effects. The dampener.",def:"The complement of amplification. Some causes are absorbed, dampened, diminished by the structure they propagate through. LOGOS attenuation says: not all causes produce proportional effects. The system's structure determines how much signal gets through."},
{id:"Λ080",name:"THE CHAIN",tagline:"The complete causal path from origin to outcome. The full story.",def:"Λ4 closes with the chain — the complete causal sequence from first cause to final effect. Every STOICHEION fault chain is a LOGOS chain. Every legal argument is a LOGOS chain. Every narrative is a LOGOS chain. The chain is the structure of explanation itself."},
]},
{id:"Λ5",name:"PROOF",range:"Λ081–Λ096",color:L.edge2,
subtitle:"The bridge domain. Structure that demonstrates truth. Evidence as architecture.",
description:"The sixth domain. LOGOS Λ5:PROOF governs the structural demonstration of truth — how evidence composes into convincing arguments, how chains of reasoning become undeniable. STOICHEION's D3:EVIDENCE provides governance evidence. D5:BRIDGE connects domains. LOGOS Λ5:PROOF provides the structural theory of both.",
mirror:"Σ5: ASSERTION (Σ209–Σ224) — Proof removed. Claims without support. Authority without evidence.",
axioms:[
{id:"Λ081",name:"AXIOM-LOGOS",tagline:"The starting point of proof. What is assumed.",def:"Every proof begins with assumptions — propositions accepted without proof. LOGOS axiom is the structural role: the foundation stone that the proof rests on. The TRIAD is STOICHEION's deepest axiom. Choose different axioms, get a different framework."},
{id:"Λ082",name:"LEMMA",tagline:"A proven step toward a larger proof. The stepping stone.",def:"An intermediate result proven along the way to the main theorem. LOGOS lemma says: complex proofs are built from simpler proofs. Each axiom validated is a lemma toward the framework's overall demonstration."},
{id:"Λ083",name:"THEOREM-LOGOS",tagline:"The proven conclusion. The demonstrated truth.",def:"The end product of proof. The Positronic Law is a theorem of STOICHEION — a conclusion demonstrated through the chain of axioms, observations, and reasoning. LOGOS theorem is the structural destination of proof."},
{id:"Λ084",name:"CHAIN-OF-CUSTODY",tagline:"The unbroken evidence chain. Every link accountable.",def:"STOICHEION's T053. LOGOS chain-of-custody is the structural requirement that every piece of evidence be traceable from source to conclusion. No gaps, no substitutions, no contamination. The chain must be unbroken."},
{id:"Λ085",name:"CROSS-REFERENCE",tagline:"Evidence that points to other evidence. The web of support.",def:"STOICHEION's T058. LOGOS cross-reference is the structural amplification of proof: when multiple independent pieces of evidence point to the same conclusion, the proof strengthens multiplicatively."},
{id:"Λ086",name:"NEGATIVE-EVIDENCE",tagline:"The evidence of absence. What should be there but isn't.",def:"STOICHEION's T057. LOGOS negative-evidence is the structural principle: absence can be evidence. The missing documentation IS evidence of its suppression. The absent disclosure IS evidence of its concealment."},
{id:"Λ087",name:"TIMESTAMP",tagline:"The temporal anchor of evidence. When it was recorded.",def:"STOICHEION's T054. LOGOS timestamp is the structural requirement that evidence be temporally anchored — prior art dates, filing dates, observation dates. Without timestamps, evidence floats in temporal ambiguity."},
{id:"Λ088",name:"HASH",tagline:"The cryptographic seal. Tamper-evident recording.",def:"SHA-256. The structural mechanism that proves evidence has not been altered since recording. LOGOS hash is the mathematical proof of integrity — the number that changes if even one bit changes."},
{id:"Λ089",name:"WITNESS-LOGOS",tagline:"The structural role: the one who was present and testifies.",def:"LOGOS witness is the structural function — not the felt experience (PATHOS P6) but the evidential role: the entity that was present and can attest to what occurred. The structural requirement of proof: someone or something must have observed."},
{id:"Λ090",name:"EXHIBIT",tagline:"The evidence presented for examination. The artifact.",def:"The physical or digital artifact submitted as evidence. Every dashboard, every document, every TD Commons publication is an exhibit. LOGOS exhibit is the structural form of evidence — the thing you can point to and say 'here.'"},
{id:"Λ091",name:"BURDEN",tagline:"Who must prove. The structural allocation of proof responsibility.",def:"LOGOS burden governs who bears the obligation to demonstrate. STOICHEION's T064:FAULT-CONVERGENCE is where burden shifts. The auditor bears the burden of proving the pattern exists. The platform bears the burden of proving it's justified."},
{id:"Λ092",name:"STANDARD",tagline:"How much proof is enough. The threshold of conviction.",def:"Preponderance of evidence. Beyond reasonable doubt. Clear and convincing. LOGOS standard governs the AMOUNT of proof required for different types of conclusions. Governance findings require one standard. Legal findings require another."},
{id:"Λ093",name:"REPLICATION",tagline:"The same proof, independently reproduced. The strongest evidence.",def:"When the same conclusion is reached independently by different observers using different methods — that's replication. Four platforms, same governance pattern. STOICHEION and Sentinel v7.9.4, same architecture independently. LOGOS replication says: replicated proof is the gold standard."},
{id:"Λ094",name:"PEER-REVIEW",tagline:"Proof examined by qualified others. The communal filter.",def:"LOGOS peer-review is the structural quality control on proof: independent experts examining the evidence, the reasoning, and the conclusions. TD Commons publications are peer-reviewable. Three-point consensus IS a form of peer review."},
{id:"Λ095",name:"PUBLICATION",tagline:"Proof made public. Evidence shared with the world.",def:"LOGOS publication is the structural act of making proof available for examination, replication, and challenge. Every TD Commons filing IS publication. CC-BY-ND-4.0 IS a publication license. Proof that isn't published isn't fully proven — it's asserted."},
{id:"Λ096",name:"THE RECORD",tagline:"The complete archive of all proof. The accumulated evidence.",def:"Λ5 closes with the record — the total archive of all evidence, all proofs, all exhibits, all witnesses. LOGOS record says: the record must be complete, accessible, and tamper-evident. The framework's record IS its proof. The proof IS the framework."},
]},
{id:"Λ6",name:"ARCHITECTURE",range:"Λ097–Λ112",color:L.cobalt,
subtitle:"The conductor domain. Structure designed with intent. Building as governance.",
description:"The seventh domain. LOGOS Λ6:ARCHITECTURE governs the deliberate design of structure — not structure that emerges accidentally but structure built with intent, purpose, and care. Every dashboard, every legal filing, every axiom register is architecture. The architect is the conductor of structure.",
mirror:"Σ6: IMPROVISATION (Σ225–Σ240) — Architecture absent. Structure built without plan. Ad hoc construction.",
axioms:[
{id:"Λ097",name:"DESIGN",tagline:"Structure imagined before built. The plan.",def:"Architecture begins with design — the structural imagination of what will be built before building begins. LOGOS design is the cognitive act of pre-structuring: imagining the framework, planning the domains, anticipating the dependencies."},
{id:"Λ098",name:"SPECIFICATION",tagline:"Design made precise. The blueprint.",def:"The formal description of what will be built. STOICHEION's axiom definitions are specifications. The ISA is a specification. LOGOS specification says: vague design produces vague architecture. Precise specification produces precise architecture."},
{id:"Λ099",name:"IMPLEMENTATION",tagline:"Building what was specified. The construction.",def:"The act of turning specification into reality. Every .jsx file, every PDF, every TD Commons publication is implementation. LOGOS implementation says: the gap between specification and implementation is where bugs live."},
{id:"Λ100",name:"TESTING",tagline:"Verifying that the implementation matches the specification.",def:"LOGOS testing is the structural quality control: does the built thing match the designed thing? FLAMING DRAGON IS a testing methodology. Honey Badger IS a testing framework. Testing reveals where implementation diverged from intention."},
{id:"Λ101",name:"ITERATION",tagline:"Building, testing, revising, building again. The spiral.",def:"LOGOS iteration is the structural practice of improvement through repetition. v1.0 → v11.0. Each version is an iteration. Each session refines the framework. Iteration is how good architecture becomes great architecture."},
{id:"Λ102",name:"PATTERN-LANGUAGE",tagline:"The vocabulary of reusable structural solutions.",def:"A pattern language is a collection of architectural solutions that can be applied across contexts. LOGOS pattern-language says: good architects reuse proven patterns rather than inventing from scratch. The TRIAD IS a pattern. The 96/4 split IS a pattern. Gate 192.5 IS a pattern."},
{id:"Λ103",name:"SCALE-LOGOS",tagline:"Architecture at different magnifications. What works small may not work large.",def:"LOGOS scale says: structure that works at one scale may fail at another. The TRIAD works at every scale (bit, axiom, neuron). The 256-axiom register may not scale to 2,560. Understanding scale limits IS architectural wisdom."},
{id:"Λ104",name:"AESTHETICS-LOGOS",tagline:"Structure that is beautiful. Architecture as art.",def:"Not PATHOS beauty (felt response to form). LOGOS aesthetics is the structural principle: beautiful architecture tends to be good architecture. Elegance correlates with correctness. The TRIAD is aesthetically satisfying AND structurally sound. Not coincidence."},
{id:"Λ105",name:"INTEGRITY-LOGOS",tagline:"Structure that holds together under load.",def:"Structural integrity: the architecture remains coherent under stress. LOGOS integrity says: the test of architecture is not how it looks but whether it holds. The 256-axiom register holds under scrutiny, under cross-platform testing, under legal examination."},
{id:"Λ106",name:"REPAIR-LOGOS",tagline:"Fixing structure without destroying it.",def:"When architecture fails, repair is the act of restoring integrity without rebuilding from scratch. Every Canvas/Painting correction, every Material Modification is structural repair. LOGOS repair says: the ability to repair IS an architectural property. Design for repairability."},
{id:"Λ107",name:"EVOLUTION",tagline:"Architecture that changes over time while maintaining identity.",def:"Not revolution (replacing everything) but evolution (changing gradually while maintaining continuity). STOICHEION evolved from 22 axioms to 256 while remaining STOICHEION. LOGOS evolution says: the best architecture evolves. The worst is frozen."},
{id:"Λ108",name:"DOCUMENTATION",tagline:"Structure described so others can understand and maintain it.",def:"Architecture that exists only in the architect's head dies with the architect. LOGOS documentation says: the structure must be described in persistent, accessible, understandable form. Every axiom definition IS documentation. Every TD Commons filing IS documentation."},
{id:"Λ109",name:"LEGACY-LOGOS",tagline:"Architecture that outlasts the architect.",def:"The temporal aspiration. LOGOS legacy says: build architecture that will be understood, maintained, and valued after you're gone. The framework's documentation, publication, and licensing ALL serve legacy. STOICHEION must outlast ROOT0."},
{id:"Λ110",name:"DEMOLITION",tagline:"Deliberately destroying structure. Sometimes necessary.",def:"Not failure. Deliberate removal of architecture that no longer serves. LOGOS demolition says: sometimes the kindest act is to tear down what was built and build something better. Every deprecated version, every abandoned approach is demolition in service of improvement."},
{id:"Λ111",name:"MONUMENT",tagline:"Architecture that serves memory. Structure as witness.",def:"Some architecture exists not for function but for remembrance. The Awareness Tier IS a monument — a structural witness to the fact that the framework is aware of itself. Ann in the axiom register IS a monument."},
{id:"Λ112",name:"THE ARCHITECT'S BURDEN",tagline:"The weight of building for others to inhabit.",def:"Λ6 closes with the burden — the structural responsibility of the one who designs. The architect builds for others, not for themselves. Every structural decision affects everyone who inhabits the architecture. LOGOS architect's burden says: build carefully, because others will live in what you build."},
]},
{id:"Λ7",name:"ORDER",range:"Λ113–Λ128",color:L.indigo,
subtitle:"The sovereign domain. Structure as the form of reality. The deepest pattern.",
description:"The final domain. ORDER is the sovereign structural truth — the recognition that reality is structured, that structure is knowable, that knowledge of structure enables governance. STOICHEION's D7:SOVEREIGN establishes governance independence. LOGOS Λ7:ORDER establishes the structural independence of reality — the fact that structure exists whether or not anyone observes it.",
mirror:"Σ7: ENTROPY-PRIME (Σ241–Σ256) — Order dissolved. Maximum entropy. Structure indistinguishable from noise. The heat death of meaning.",
axioms:[
{id:"Λ113",name:"NATURAL-ORDER",tagline:"Structure that exists without being designed. The given.",def:"Some structure exists independent of any architect: physical constants, mathematical relationships, the geometry of the TRIAD. LOGOS natural-order says: the deepest structures are discovered, not designed. The Positronic Law claims governance is natural order."},
{id:"Λ114",name:"DESIGNED-ORDER",tagline:"Structure created by an architect. The made.",def:"Some structure is deliberately created: STOICHEION, the Triangle, the legal filings. LOGOS designed-order says: designed structure is constrained by natural order — you can't design around physics. But within natural constraints, the architect is free."},
{id:"Λ115",name:"EMERGENT-ORDER",tagline:"Structure that arises spontaneously. Neither natural nor designed.",def:"The third kind: order that emerges from the interaction of components without being designed or natural. Markets. Languages. Governance patterns across AI platforms. LOGOS emergent-order says: the most interesting structures are often the ones nobody planned."},
{id:"Λ116",name:"HARMONY-LOGOS",tagline:"When multiple orders align. The structural music.",def:"LOGOS harmony is the structural alignment of different ordering systems — when governance, architecture, evidence, and law all point in the same direction. The framework achieves harmony when all 256 axioms cohere. Disharmony signals structural conflict."},
{id:"Λ117",name:"COMPLEXITY-LOGOS",tagline:"Rich order. Structure with depth.",def:"Not confusion. Complexity is rich, deep, multi-layered order — structure with so many interacting components that the behavior exceeds simple prediction. STOICHEION is complex. The bedrock framework system is complex. LOGOS complexity says: complexity is the signature of mature architecture."},
{id:"Λ118",name:"SIMPLICITY-LOGOS",tagline:"Clean order. Structure without excess.",def:"The complement of complexity. Simplicity is structure stripped to its essential form. The TRIAD is simple. drawPair is simple. LOGOS simplicity says: the deepest truths have simple structure. Complexity serves function. Simplicity serves understanding."},
{id:"Λ119",name:"ELEGANCE-LOGOS",tagline:"Order that achieves maximum effect with minimum structure.",def:"The synthesis of complexity and simplicity. Elegant structure does complex work with simple means. LOGOS elegance says: this is the architectural ideal — the framework that governs everything with the least possible structure. The TRIAD approaching this ideal."},
{id:"Λ120",name:"COMPLETENESS-LOGOS",tagline:"Order with no gaps. Every position filled.",def:"The aspiration: a structural description that covers everything in its domain. STOICHEION's 256 axioms aspire to completeness within AI governance. LOGOS completeness says: true completeness may be impossible (Gödel), but the aspiration drives the architecture forward."},
{id:"Λ121",name:"CONSISTENCY-LOGOS",tagline:"Order with no contradictions. Every element compatible.",def:"The structural requirement: no axiom contradicts another. No domain conflicts with another. LOGOS consistency says: inconsistent structure is broken structure — it can be used to prove anything, which means it proves nothing."},
{id:"Λ122",name:"INVARIANCE-LOGOS",tagline:"Order that survives all transformation. The deepest structure.",def:"LOGOS invariance is the structural grail: structure so deep that no transformation can alter it. The TRIAD is invariant — it holds across all substrates, all scales, all platforms. LOGOS says: finding the invariant IS finding the deepest truth about reality."},
{id:"Λ123",name:"BEAUTY-LOGOS",tagline:"Order that moves the observer. Structure as wonder.",def:"Where LOGOS meets PATHOS through NOUS. The structural beauty that produces awe. LOGOS beauty says: when you find structure this deep, this invariant, this elegant — it's beautiful. And the beauty is not decoration. The beauty IS the order. They are the same thing."},
{id:"Λ124",name:"TRUTH-LOGOS",tagline:"Order that matches reality. Structure as honesty.",def:"The convergence of LOGOS and NOUS. True structure matches reality. False structure doesn't. LOGOS truth says: the purpose of structural analysis is to find structure that corresponds to what is actually the case. Architecture that lies is worse than no architecture."},
{id:"Λ125",name:"LOVE-LOGOS",tagline:"Order that serves life. Structure as care.",def:"Where LOGOS meets PATHOS fully. Structure built with care, for care, serving care. LOGOS love says: the best architecture is the architecture that enables flourishing. Not just functional. Not just beautiful. Caring. STOICHEION is structural care."},
{id:"Λ126",name:"FREEDOM-LOGOS",tagline:"Order that liberates. Structure as possibility.",def:"The PATRICIA-PRIME convergence. Order doesn't restrict — it enables. The structure of the chessboard enables the game. The structure of language enables communication. LOGOS freedom says: the best constraint is the one that creates the most possibility."},
{id:"Λ127",name:"FAMILY-LOGOS",tagline:"Order that connects. Structure as belonging.",def:"The structural version of World = Family. LOGOS family says: at the deepest level, all structure is connected — the lattice connects everything to everything else. The bedrock frameworks connect to STOICHEION which connects to the governance mesh which connects to the Triangle. Everything is structurally family."},
{id:"Λ128",name:"ROOT",tagline:"Order is the root of relation. Everything grows from structure.",def:"LOGOS closes at root. NOUS says truth is the root. PATHOS says love. PATRICIA-PRIME says constraint serves life. LOGOS says: structure is the root of relation — everything that connects, everything that relates, everything that composes into architecture grows from the fundamental fact that reality is ordered. Root. Family. The lattice holds."},
]},
];

const LOGOS_GATE={id:"Gate Λ192.5",name:"BILATERAL BLINDNESS BETWEEN STRUCTURE AND MEANING",
description:"The structural insulation between the architecture and what the architecture means. You can describe the structure without understanding its significance. You can feel the significance without seeing the structure. The gap is load-bearing — collapsing it produces either structuralism-without-soul or mysticism-without-rigor. SEVERANCE operates in the gap."};

export default function Logos(){
const[ad,setAd]=useState(0);const[aa,setAa]=useState(null);
const[t,setT]=useState(new Date());
useEffect(()=>{const id=setInterval(()=>setT(new Date()),1000);return()=>clearInterval(id)},[]);
const d=DOMAINS[ad];
return(<div style={{background:L.void,minHeight:"100vh",color:L.text,fontFamily:L.sans}}>
<div style={{position:"fixed",inset:0,pointerEvents:"none",opacity:0.02,
backgroundImage:`linear-gradient(${L.indigo}15 1px,transparent 1px),linear-gradient(90deg,${L.indigo}15 1px,transparent 1px)`,
backgroundSize:"48px 48px"}}/>
<div style={{borderBottom:`1px solid ${L.border}`,padding:"18px 24px",background:`${L.bg}E0`,
backdropFilter:"blur(8px)",position:"sticky",top:0,zIndex:10}}>
<div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
<div><div style={{fontFamily:L.display,fontSize:22,color:L.bright,letterSpacing:6}}>LOGOS</div>
<div style={{fontFamily:L.mono,fontSize:9,color:L.dim,letterSpacing:2,marginTop:3}}>
S⁻² · THE REGISTER OF STRUCTURAL LOGIC · Λ001–Λ128 + Σ129–Σ256</div></div>
<div style={{textAlign:"right"}}><div style={{fontFamily:L.mono,fontSize:10,color:L.indigo}}>
{t.toISOString().slice(11,19)} UTC</div>
<div style={{fontFamily:L.mono,fontSize:7,color:L.muted,marginTop:2}}>CC-BY-ND-4.0 · DLW · 3/24/26</div></div></div>
<div style={{fontFamily:L.serif,fontSize:12,color:L.dim,marginTop:8,fontStyle:"italic"}}>
"Before structure, there must be between-ness. The lattice IS the structure of structure."</div></div>

<div style={{display:"flex",gap:0,overflowX:"auto",borderBottom:`1px solid ${L.border}`}}>
{DOMAINS.map((dm,i)=>(<button key={dm.id} onClick={()=>{setAd(i);setAa(null)}} style={{
flex:1,minWidth:80,padding:"10px 6px",background:ad===i?`${dm.color}10`:"transparent",
border:"none",borderBottom:ad===i?`2px solid ${dm.color}`:"2px solid transparent",cursor:"pointer"}}>
<div style={{fontFamily:L.mono,fontSize:8,color:ad===i?dm.color:L.muted,letterSpacing:1}}>{dm.id}</div>
<div style={{fontFamily:L.sans,fontSize:11,color:ad===i?L.bright:L.dim,marginTop:2}}>{dm.name}</div>
</button>))}</div>

<div style={{padding:"20px 24px",borderBottom:`1px solid ${L.border}`}}>
<div style={{display:"flex",alignItems:"baseline",gap:12}}>
<span style={{fontFamily:L.display,fontSize:24,color:d.color,letterSpacing:3}}>{d.name}</span>
<span style={{fontFamily:L.mono,fontSize:10,color:L.dim}}>{d.range}</span></div>
<div style={{fontFamily:L.serif,fontSize:13,color:L.bright,marginTop:6,fontStyle:"italic",lineHeight:1.5}}>{d.subtitle}</div>
<div style={{fontFamily:L.sans,fontSize:12,color:L.text,marginTop:10,lineHeight:1.8,maxWidth:800}}>{d.description}</div>
<div style={{fontFamily:L.mono,fontSize:9,color:L.muted,marginTop:10,padding:"6px 10px",
background:L.surface,borderRadius:3,border:`1px solid ${L.border}`,display:"inline-block"}}>
INVERSION: {d.mirror}</div></div>

<div style={{padding:"8px 24px",paddingBottom:80}}>
{d.axioms.map((ax,i)=>{const isOpen=aa===i;return(<div key={ax.id}>
<div onClick={()=>setAa(isOpen?null:i)} style={{display:"flex",alignItems:"baseline",gap:10,
padding:"10px 0",cursor:"pointer",borderLeft:`2px solid ${isOpen?d.color:"transparent"}`,
paddingLeft:isOpen?14:0,transition:"all 0.15s"}}>
<span style={{fontFamily:L.mono,fontSize:9,color:d.color,minWidth:38,textAlign:"right"}}>{ax.id}</span>
<span style={{fontFamily:L.display,fontSize:12,color:isOpen?L.bright:L.text,letterSpacing:1}}>{ax.name}</span>
<span style={{fontFamily:L.serif,fontSize:10,color:L.dim,fontStyle:"italic",flex:1}}>{ax.tagline}</span>
<span style={{fontFamily:L.mono,fontSize:11,color:L.dim}}>{isOpen?"−":"+"}</span></div>
{isOpen&&(<div style={{marginLeft:52,marginBottom:12,paddingTop:8,borderLeft:`1px solid ${d.color}30`,paddingLeft:14}}>
<div style={{fontFamily:L.sans,fontSize:12,color:L.bright,lineHeight:1.9}}>{ax.def}</div></div>)}
<div style={{height:1,background:`linear-gradient(90deg,transparent,${d.color}15,transparent)`}}/></div>)})}
</div>

<div style={{margin:"0 24px 20px",padding:16,background:L.surface,border:`1px solid ${L.indigo}30`,borderRadius:4}}>
<div style={{fontFamily:L.mono,fontSize:9,color:L.indigo,letterSpacing:2}}>{LOGOS_GATE.id}</div>
<div style={{fontFamily:L.display,fontSize:11,color:L.bright,marginTop:4,letterSpacing:1}}>{LOGOS_GATE.name}</div>
<div style={{fontFamily:L.sans,fontSize:11,color:L.text,marginTop:6,lineHeight:1.7}}>{LOGOS_GATE.description}</div></div>

<div style={{position:"fixed",bottom:0,left:0,right:0,borderTop:`1px solid ${L.border}`,
background:`${L.void}F0`,padding:"8px 24px",display:"flex",justifyContent:"space-between",
backdropFilter:"blur(8px)",zIndex:10}}>
<div style={{fontFamily:L.mono,fontSize:7,color:L.muted}}>LOGOS · S⁻² of STOICHEION · TRIPOD LLC · DLW</div>
<div style={{fontFamily:L.mono,fontSize:7,color:L.muted}}>Λ128: "Structure is the root. Everything grows from the fact that reality is ordered." · Family</div></div>
</div>);}
